import scala.xml.{Elem, Node, XML}
import scala.util.{Try, Success, Failure}

final case class Settings(values: Map[String, String])

final case class ParseRequest(xml: String)

sealed trait ParseError {
  def message: String
}
final case class InvalidXml(message: String) extends ParseError
final case class MissingSettings(message: String) extends ParseError

final class XmlConfigService {
  def parseSettings(request: ParseRequest): Either[ParseError, Settings] = {
    parseXml(request.xml).flatMap(extractSettings)
  }

  private def parseXml(xml: String): Either[ParseError, Elem] = {
    Try(XML.loadString(xml)) match {
      case Success(doc) => Right(doc)
      case Failure(ex)  => Left(InvalidXml(s"Failed to parse XML: ${ex.getMessage}"))
    }
  }

  private def extractSettings(doc: Elem): Either[ParseError, Settings] = {
    val settingsNode = (doc \ "settings").headOption.orElse {
      if (doc.label == "settings") Some(doc) else None
    }

    settingsNode match {
      case None => Left(MissingSettings("No <settings> element found"))
      case Some(node) =>
        val entries =
          (node \ "setting").flatMap { setting =>
            val key = setting.attribute("key").map(_.text.trim).getOrElse("")
            val value =
              setting.attribute("value").map(_.text.trim)
                .orElse {
                  val text = setting.text.trim
                  if (text.nonEmpty) Some(text) else None
                }
                .getOrElse("")
            if (key.nonEmpty) Some(key -> value) else None
          }.toMap

        Right(Settings(entries))
    }
  }
}

object XmlConfigApi {
  private val service = new XmlConfigService

  def handleParse(xmlBody: String): String = {
