          s""""$k":"${escapeJson(v)}""""
        }.mkString(",")
        s"""{"status":"ok","settings":{$items}}"""
      case Left(err) =>
        s"""{"status":"error","message":"${escapeJson(err.message)}"}"""
    }
  }

  private def escapeJson(value: String): String =
    value
      .replace("\\", "\\\\")
      .replace("\"", "\\\"")
      .replace("\b", "\\b")
      .replace("\f", "\\f")
      .replace("\n", "\\n")
      .replace("\r", "\\r")
      .replace("\t", "\\t")
